<span class="line"><span style="color:#CDD6F4;">        defines </span><span style="color:#94E2D5;">=</span><span style="color:#89B4FA;"> defaultdict</span><span style="color:#9399B2;">(</span><span style="color:#FAB387;font-style:italic;">set</span><span style="color:#9399B2;">)</span><span style="color:#6C7086;font-style:italic;">  # tag -&gt; set of files that define it</span></span>
